<template>
    <section>
    
        <tg-list :IsShowAction="true" :showCheckBox="true" ModuleName="Billing" :listType="['List']"
            :RenderRowActionMethod="renderActions" SubModuleCode="Billing" IdentityColumn="RATE_SCHEDULE_ID"
            :ListData="RateScheduledeListing" :HeaderData="Headers" :callbackfunction="FetchData"
            :HeaderButtons="listheaderbuttons" :TotalRecords="TotalRecords" :ListDataCallBackFunction="FetchData"
            :LegendArray="[]" :SortExp="sortExp" :SortBy="sortBy" :NorecordfoundText="$t('NoRecordfound')"
            v-on:LeftsearchButtonClick="[]" v-on:PagerButtonClick="pagerMethod" :isShowHeaderText="true"
            v-on:ActionButtonClick="actionButtonClick" :HeaderText="$t('RateSchedule')"
            v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:SortdataButtonClick="sortdata">
            <template v-slot:slotdata="{ data }">
                <template v-if="data.column.COLUMN_NAME == 'AMOUNT'">
                    <a href="javascript:void(0);"  class="task-dec" @click="EditRateCode(data.row)">{{ data.row.AMOUNT != null ?
                        parseFloat(data.row.rate).toFixed(2) : '--' }} </a>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'MODIFIED_AT'">
                    <td class="text-center single-action tourguide_a" v-if="data.row.MODIFIED_AT">
                        {{ $options.filters.formatDateTime(toUserDateTime(data.row.MODIFIED_AT,timeZone)) }}
                    </td>
                    <td class="text-center single-action tourguide_a" v-else>--</td>
                </template>
                 <template v-if="data.column.COLUMN_NAME == 'CREATED_AT'">
                    <td class="text-center single-action tourguide_a" v-if="data.row.CREATED_AT">
                        {{ $options.filters.formatDateTime(toUserDateTime(data.row.CREATED_AT,timeZone)) }}
                    </td>
                    <td class="text-center single-action tourguide_a" v-else>--</td>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'STATUS_ID'">
                    <div>
                        <div class="cstm-drop-btn">
                            <select v-model="data.row.STATUS_ID" @change="UpdataStatus(data.row.STATUS_ID,data.row.RATE_SCHEDULE_ID)" :class="data.row.STATUS_ID == 1001 ? 'ddlupdatestatus w-80 btn-success' : 'ddlupdatestatus w-80 btn-danger'">
                                <option value="1001" selected="selected">{{ $t("Active") }}</option>
                                <option value="1002">{{ $t("Inactive") }}</option>
                            </select>
                        </div>
                    </div>
                </template>
            </template>
        </tg-list>
        <ServiceRatesList v-if="isServices" :Id="clientplanmappingid" :PlanId="PlanId" :ClientId="ClientId"></ServiceRatesList>
        <AddRateForUsic v-if="IsAddRate  " @CloseRateCode="CloseRateCode"></AddRateForUsic> 

        <ViewHistory v-if="isViewHistory" :Id="clientplanmappingid"></ViewHistory>
    </section>
</template>
<script>
import DataService from "../../../services/DataService";
import ServiceRatesList from "../../Client/ClientDetails/ServiceRatesList.vue"
import ViewHistory from "../../Client/ClientDetails/ViewHistoryRateSchedule.vue"
import SubscriptionRateSchedule from "./SubscriptionRateSchedule.vue";
import AddRateForUsic from "../../Client/ClientDetails/AddRateForUsic.vue";
export default {
    components: { ServiceRatesList, ViewHistory, SubscriptionRateSchedule,AddRateForUsic },
     props: {
    ClientData: Object,
    ClientId: Number,
    IsClient: String,  
    activeTab: String, 
  },
    data() {
        return {
            RateScheduledeListing: [],
            TotalRecords: 0,
            pageSize: 10,
            pageNum: 1,
            sortBy: '',
            CurrentPage: 1,
            TotalPages: 0,
            sortExp: '',
            noRecords: false,
            Headers: [
                {
                    "COLUMN_NAME": "CLIENT_NAME",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('Contract'),
                    "DISPLAY_ORDER": 1
                },
                {
                    "COLUMN_NAME": "WORK_CODE",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('Work Code'),
                    "DISPLAY_ORDER": 2
                },
                {
                    "COLUMN_NAME": "UTILITY_NAME",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('Utility Name'),
                    "DISPLAY_ORDER": 3
                },
                {
                    "COLUMN_NAME": "STATE_NAME",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('State'),
                    "DISPLAY_ORDER": 4
                },
                  {
                    "COLUMN_NAME": "AMOUNT",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('Rate'),
                    "DISPLAY_ORDER": 4
                },
                {
                    "COLUMN_NAME": "BillingCode",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('Customer Work Code'),
                    "DISPLAY_ORDER": 5
                },
                {
                    "COLUMN_NAME": "STATUS_ID",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('Status'),
                    "DISPLAY_ORDER": 6,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "START_DATE",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('Start Date'),
                    "DISPLAY_ORDER": 7
                },
                {
                    "COLUMN_NAME": "END_DATE",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('End Date'),
                    "DISPLAY_ORDER": 8
                },
                {
                    "COLUMN_NAME": "CREATED_BY",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('Created By'),
                    "DISPLAY_ORDER": 9
                },
                 {
                    "COLUMN_NAME": "CREATED_AT",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('Created Date'),
                    "DISPLAY_ORDER": 10,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "MODIFIED_BY",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('Modified By'),
                    "DISPLAY_ORDER": 11
                },
                {
                    "COLUMN_NAME": "MODIFIED_AT",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('Modified Date'),
                    "DISPLAY_ORDER": 12,
                    settings: {
                        isInSlot: true
                    }
                },

            ],
            listheaderbuttons: [  
            {
                title: 'Inactive',
                iconClass: 'fa fa-close',
                callbackfunction: 'Inactive',
                additionalClass: '',
                isdisabled: true,
                isvisible: true,            
                isEnabledOnSelectedRow: true
            },
              {
                title: 'AddRateSchedule',
                iconClass: 'fa fa-plus',
                callbackfunction: 'AddRateSchedule',
                additionalClass: '',
                isdisabled: true,
                isvisible: true,            
                isEnabledOnSelectedRow: true
            },
            {
                id: 'Update',
                title: 'Update',
                iconClass: 'fa fa-pencil',
                callbackfunction: 'Update',
                isdisabled: false,
                isvisible: true        
            },
            {
                id: 'CopyRate',
                title: 'Copy Rate',
                iconClass: 'fa fa-files-o',
                callbackfunction: 'CopyRate',
                isdisabled: false,
                isvisible: true        
            },
            {
                id: 'ViewHistory',
                title: 'View History',
                iconClass: 'fa fa-eye',
                callbackfunction: 'ViewHistory',
                isdisabled: false,
                isvisible: true        
            },

              {
                id: 'Remove',
                title: 'Remove',
                iconClass: 'fa fa-eye',
                callbackfunction: 'Remove',
                isdisabled: false,
                isvisible: true        
            },

            
            ],
            listActions:
                [
                    {
                        title: 'Edit',
                        href: 'javascript:void(0)',
                        icon: 'fa fa-pencil text-info action-icon',
                        callbackfunction: 'edit',
                        isDisabled: false,
                        additionalSpan: ''
                    },
                    {
                        title: 'View History',
                        href: 'javascript:void(0)',
                        icon: 'fa fa-eye',
                        isDisabled: false,
                        callbackfunction: 'viewHistory',
                        additionalSpan: ''
                    },
                ],
            isServices: false,
            IsAddRate:false,
            clientplanmappingid: 0,
            PlanId:0,
            isViewHistory: false,
            IsSubscriptionBilling: false,
            IsUtilityBilling: false,
            // isBillingType: false,
            timeZone:'',
             RateObj: null,
        }
    },
    async created() {
        var vm = this;
        this.timeZone =this.GetUserInfo.TimeZone;
        await vm.CheckExtraFeatures();
         this.isBillingType = localStorage.getItem("billingType") === "USIC";
        if (this.isBillingType) {
      this.FetchData(); 
    }
    },
  
  
    methods: {
       commonHeaderButtonClick(event) {
         switch (event.callbackfunction) {
            case "Inactive":
                    this.UpdataStatus(1002);
                    break;
                     case "AddRateSchedule":
                    this.AddRateSchedule();
                    break;
            }
            
            
        },
        UpdataStatus(StatusID) {
            debugger;
            var vm = this;
            var val = "";
            $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(function () {
                if (val.length > 0)
                    val += ',';
                val += $(this).val();
            });
            if (val.length > 0) {
                vm.confirmR(vm.$t("AreYouSureToUpdateStatus"), true, false, function () {
                        var postJSON = {
                            Id: val,
                            StatusId: StatusID,
                            TableName: "TALYGEN_BE_rate_schedule",
                            PrimaryColumn: "rate_schedule_id"
                        };
                    var objectPostString = JSON.stringify(postJSON);
                    DataService.UpdateRateScheduleStatus(objectPostString).then(response => {
                        if (response.status === 200) {
                                vm.ShowAlert(
                                    vm.$t('RecordUpdatedSuccessfully'),
                                    "success",
                                    true,
                                    vm.$t("Alert")
                                );
                                vm.FetchData();
                            }
                    });
                });
            }
            else {
                vm.ShowAlert(vm.$t('Selectanyrecordtodelete', [vm.$t('Goal')]), "failure", true, vm.$t('Alert'));
            }
            },

        async CheckExtraFeatures() {
            debugger
            var vm = this;
            const params = `featureCode=GET_EXTRA_FEATURE_BILLING&outputType=list`;
            try {
                const response = await DataService.CheckExtraFeatures(params);
                if (response.data) {
                    const features = JSON.parse(response.data);
                    features.forEach(feature => {
                        if (feature.FEATURE_CODE === 'SUBSCRIPTION_BILLING') {
                            vm.IsSubscriptionBilling = true;
                        }
                        if (feature.FEATURE_CODE === 'UTILITY_BILLING') {
                            vm.IsUtilityBilling = true;
                        }
                    });
                }
            } catch (error) {

                console.log("Error checking extra features:", error);
            }
        },

        async FetchData() {
            debugger
            var vueObj = this;
            vueObj.PlanListing = [];
            var url = `clientId=531039&pageSize=${vueObj.pageSize}&pageNum=${vueObj.pageNum}&sortBy=${vueObj.sortBy}&sortExp=${vueObj.sortExp}&search=${vueObj.searchCondition}&isBillingType=${vueObj.isBillingType}&clientIds=${vueObj.clientIds ?? ''}&workCodes=${vueObj.workCodes ?? ''}&searchByState=${vueObj.searchByState ?? ''}&searchByUtility=${vueObj.searchByUtility ?? ''}&userDate=2022-01-19`;
            await DataService.GetWorkCodeMappingList(url).then(function (response) {
                 debugger
                if (response.data != "" && response.data != null) {
                    if (response.data.result.length > 0) {
                        vueObj.RateScheduledeListing = response.data.result;

                        vueObj.TotalRecords = response.data.result[0].TOTALRECORDS;
                        vueObj.TotalPages = Math.ceil(vueObj.TotalRecords / vueObj.pageSize);
                        vueObj.CurrentPage = vueObj.pageNum;
                        vueObj.noRecord = false;
                    } else {
                        vueObj.noRecord = true;
                        vueObj.TotalRecords = 0
                        vueObj.RateScheduledeListing = [];
                    }
                }
                else {
                    vueObj.noRecord = true;
                    vueObj.TotalRecords = 0
                    vueObj.PlanListing = [];
                }
            })
        },
        actionButtonClick(callbackfunction, item) {
            var vm = this;
            switch (callbackfunction) {
                case 'edit':
                    vm.edit(item);
                    break;
                case 'viewHistory':
                    vm.viewHistory(item);
                    break;

            }
        },
        renderActions(row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach(actionItem => {
                let action = { ...actionItem };
                switch (action.title) {
                        case 'Edit':
                        action.isVisible = true;
                        action.isDisabled = row.payment_type == "One Time" && row.client_plan_mapping_id>0 ? true : false;
                        break
                    case 'View History':
                        action.isVisible = true;
                        break;


                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
        edit(data) {

            this.clientplanmappingid = data.client_plan_mapping_id
            this.isServices = true
        },
//   EditRateCode(itm) {
//     debugger
//     if (!this.isBillingType) return;

//     this.RateObj = itm;
//     this.IsAddRate = true;
//     this.FetchData();
// },
  AddRateSchedule () {
    debugger
            var vm = this;
            //vm.EditData =[];
            vm.IsAddRate = true;
        },
  CloseRateCode() {
            var ths = this;
            ths.IsAddRate = false;
            ths.FetchData();
        },
        async viewHistory(data) {
            this.clientplanmappingid = data.client_plan_mapping_id;
            this.isViewHistory = true
        },
        close() {
            this.isServices = false
        },
       
        sortdata(sortBy) {
            this.sortBy = sortBy;
            var sortExp = 'ASC';
            if (this.sortExp == 'ASC') {
                sortExp = 'DESC';
            }
            this.sortExp = sortExp;
            this.sortBy = sortBy;
            this.sortExp = sortExp;
            this.pageNum = 1;
            this.GroupStart = this.pageNum;
            this.GroupEnd = this.pageNum + 2;
            this.FetchData();
        },
        pagerMethod: function (value) {
            this.pageSize = value.PageSize;
            this.pageNum = value.PageNumber;
            this.FetchData();
        },
    }
}
</script>